import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ArrowUpward, ArrowDownward } from '@mui/icons-material';
import response from './response.json';

interface FlightStatus {
  flightNumber: string;
  departure: {
    airport: string;
    scheduledTime: string;
    actualTime: string;
    gate: string;
    status: string;
  };
  arrival: {
    airport: string;
    scheduledTime: string;
    estimatedTime: string;
    gate: string;
    status: string;
  };
  delayInfo: {
    departureDelay: number;
    arrivalDelay: number;
  };
}

export default function Widget() {
  const data = response.data as FlightStatus;
  const departureDelayPositive = data.delayInfo.departureDelay > 0;
  const arrivalDelayPositive = data.delayInfo.arrivalDelay > 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Flight Number
            </Typography>
            <Typography variant="h5" fontWeight={600} sx={{ color: '#007BFF' }}>
              {data.flightNumber}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Departure
            </Typography>
            <Typography variant="body1" fontWeight={500}>
              {data.departure.airport}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              <Chip label={`Gate: ${data.departure.gate}`} size="small" sx={{ bgcolor: '#E3F2FD', color: '#1976D2' }} />
              <Typography variant="body2" sx={{ color: departureDelayPositive ? '#EF4444' : '#10B981' }}>
                {departureDelayPositive ? <ArrowUpward fontSize="small" /> : <ArrowDownward fontSize="small" />}
                {data.departure.status} ({data.delayInfo.departureDelay} min)
              </Typography>
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Arrival
            </Typography>
            <Typography variant="body1" fontWeight={500}>
              {data.arrival.airport}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              <Chip label={`Gate: ${data.arrival.gate}`} size="small" sx={{ bgcolor: '#FFF8E1', color: '#FFB300' }} />
              <Typography variant="body2" sx={{ color: arrivalDelayPositive ? '#EF4444' : '#10B981' }}>
                {arrivalDelayPositive ? <ArrowUpward fontSize="small" /> : <ArrowDownward fontSize="small" />}
                {data.arrival.status} ({data.delayInfo.arrivalDelay} min)
              </Typography>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
